from enna_hcp_configuration.texts import TextObject

dialog_message__radio_permission_audio_capture = TextObject(bs_BA="Za korištenje ove funkcije moraju biti dozvoljena ovlaštenja za analizu radio signala. Želite li promijeniti ovlaštenje\nu postavkama?", cs_CZ="Abyste mohli tuto funkci používat, musíte povolit oprávnění pro analýzu rádiového signálu. Chcete změnit\noprávnění v nastaveních?", da_DK="Der skal frigives autorisationer til at analysere radiosignalet for at kunne anvende denne funktion. Vil du ændre\nautorisation i indstillingerne?", de_DE="Um diese Funktion nutzen zu können, müssen Berechtigungen für die Analyse des Radiosignals freigegeben\nwerden. Möchtest du die Berechtigung in den Einstellungen ändern?", el_GR="Για να μπορέσει να χρησιμοποιηθεί αυτή η λειτουργία, πρέπει να χορηγηθούν δικαιώματα για την ανάλυση του\nραδιοφωνικού σήματος. Θέλετε να αλλάξετε το δικαίωμα στις ρυθμίσεις;", en_GB="To use this function, authorisations for the analysis of the radio signal must be issued. Do you wish to change the\nauthorisation in the settings?", es_ES="Para poder utilizar esta función hay que habilitar permisos para el análisis de la señal de radio. ¿Desea modificar\nel permiso en los ajustes?", fi_FI="Tämän toiminnon käyttämiseksi on myönnettävä oikeudet radiosignaalin analyysiin. Haluatko muuttaa oikeutta\nasetuksista?", fr_FR="Pour pouvoir utiliser cette fonction, il faut autoriser l'analyse du signal radio. Souhaitez-vous modifier\nl'autorisation dans les réglages?", hr_HR="Kako biste koristili ovu funkciju, potrebno je aktivirati odobrenja za analizu radiosignala. Želite li promijeniti\nodobrenje u postavkama?", hu_HU="Ennek a funkciónak a használatához engedélyt kell adni a rádiójel elemzésére. Módosítani szeretnéd az\njogosultságot a beállításokban?", it_IT="Per poter utilizzare questa funzione è necessario concedere le autorizzazioni per l'analisi del segnale radio.\nModificare l'autorizzazione nelle impostazioni?", nl_NL="Om deze functie te kunnen gebruiken moeten autorisaties voor de analyse van het radiosignaal worden\nvrijgegeven. Wil je de autorisatie in de instellingen veranderen?", no_NO="Du må gi tilgang til analyse av radiosignalet for å bruke denne funksjonen. Vil du endre tilgangstillatelsene i\ninnstillingene?", pl_PL="Do korzystania z tej funkcji wymagane jest aktywowanie uprawnień do analizy sygnału radiowego. Czy chcesz\nzmienić uprawnienie w ustawieniach?", pt_PT="Para poderes utlizar esta função é necessário ativar as permissões para a análise do sinal rádio. Queres alterar as\npermissões nos ajustes?", ro_RO="Pentru a putea utiliza această funcţie, trebuie acordate permisiuni pentru analiza semnalului radio. Doriţi să\nmodificaţi permisiunea în setări?", ru_RU="Для использования этой функции необходимо предоставить разрешения на анализ радиосигнала. Хотите\nизменить разрешение в настройках?", sk_SK="Aby ste mohli používať túto funkciu, musia sa schváliť oprávnenia na analýzu rádiového signálu. Chcete zmeniť\noprávnenie v nastaveniach?", sl_SI="Za uporabo te funkcije je treba odobriti pooblastila za analizo radijskega signala. Ali želite v nastavitvah\nspremeniti pooblastilo?", sr_RS="Da biste mogli da koristite ovu funkciju, potrebno je odobriti analizu radio signala. Da li želite da promenite\ndozvolu u podešavanja?", sv_SE="För att kunna använda denna funktion måste du tilldela behörighet för analys av radiosignalen. Vill du ändra\nbehörigheten i inställningarna?", tr_TR="Bu fonksiyonu kullanabilmek için, radyo sinyalinin analizi için yetkiler serbest bırakılmalıdır. Ayarlardaki yetkiyi\ndeğiştirmek istiyor musun?", uk_UA="Для використання цієї функції необхідно надати дозвіл на аналіз радіосигналу. Хочете змінити дозвіл у\nнастройках?")
dialog_message__radio_permission_location_services = TextObject(bs_BA="Za korištenje ove funkcije se moraju dozvoliti podaci o poziciji. Želite li promijeniti ovlaštenje u postavkama?", cs_CZ="Abyste mohli tuto funkci používat, musíte povolit data o poloze. Chcete změnit oprávnění v nastaveních?", da_DK="Positionsdata skal frigives for at kunne anvende denne funktion. Vil du ændre autorisation i indstillingerne?", de_DE="Um diese Funktion nutzen zu können, müssen Positionsdaten freigegeben werden. Möchtest du die Berechtigung\nin den Einstellungen ändern?", el_GR="Για να μπορέσετε να χρησιμοποιήσετε αυτή τη λειτουργία, πρέπει να εγκριθεί η χρήση στοιχείων θέσης. Θέλετε να\nαλλάξετε την εξουσιοδότηση στις ρυθμίσεις;", en_GB="To use this function, positional data must be transmitted. Do you wish to change the authorisation in the settings?", es_ES="Para poder utilizar esta función hay que habilitar los datos de posición. ¿Desea modificar el permiso en los\najustes?", fi_FI="Tämän toiminnon käyttäminen edellyttää sijaintitietojen aktivoimista. Haluatko muuttaa oikeutta asetuksista?", fr_FR="Pour pouvoir utiliser cette fonction, l'accès aux coordonnées géographiques doit être autorisé. Souhaitez-vous\nmodifier l'autorisation dans les réglages?", hr_HR="Kako biste koristili ovu funkciju, potrebno je dopustiti podatke o poziciji. Želite li promijeniti odobrenje u\npostavkama?", hu_HU="Ennek a funkciónak a használatához engedélyezni kell a helyadatokat. Módosítani szeretnéd az jogosultságot a\nbeállításokban?", it_IT="Per poter utilizzare questa funzione è necessario consentire l'accesso ai dati sulla posizione. Desidera modificare\nl'autorizzazione nelle impostazioni?", nl_NL="Om deze functie te kunnen gebruiken, moeten de positiegegevens worden vrijgegeven. Wilt u de autorisatie in de\ninstellingen wijzigen?", no_NO="Du må gi tilgang til posisjonsdata for å bruke denne funksjonen. Vil du endre tillatelsene i innstillingene?", pl_PL="Aby móc korzystać z tej funkcji, należy aktywować dane położenia. Czy chcesz zmienić uprawnienie w\nUstawieniach?", pt_PT="Para poder utilizar esta função é necessário autorizar os dados de posição. Desejas alterar a permissão nos\najustes?", ro_RO="Pentru a putea utiliza această funcţie, trebuie autorizate datele de poziţie. Doriţi să modificaţi drepturile în\nsetări?", ru_RU="Чтобы иметь возможность использовать эту функцию, данные о местоположении должны быть\nразблокированы. Хотите изменить разрешение в настройках?", sk_SK="Aby ste mohli používať túto funkciu, musíte schváliť údaje o polohe. Chceš zmeniť oprávnenie v nastaveniach?", sl_SI="Za uporabo te funkcije je treba odobriti podatke o lokaciji. Ali želite v nastavitvah spremeniti pooblastilo?", sr_RS="Da biste koristili ovu funkciju moraju da budu dozvoljeni podaci za poziciju. Da li želite da izmenite ovlašćenje u\npodešavanjima?", sv_SE="För att kunna använda den här funktionen måste användning av platsdata godkännas. Vill du ändra\nbehörigheterna i inställningarna?", tr_TR="Bu fonksiyonu kullanabilmek için, konum bilgileri serbest bırakılmalıdır. Ayarlardaki yetkiyi değiştirmek istiyor\nmusun?", uk_UA="Щоб мати можливість використовувати цю функцію, слід активувати дані про місцезнаходженняі. Бажаєте\nзмінити дозвіл у настройках?")
